import{_ as a,o as e,c as i,a0 as o}from"./chunks/framework.CWk8AOcY.js";const c=JSON.parse('{"title":"什么是 Node、集群与调度","description":"","frontmatter":{},"headers":[],"relativePath":"guide/concepts/node-cluster-scheduling.md","filePath":"zh/guide/concepts/node-cluster-scheduling.md"}'),r={name:"guide/concepts/node-cluster-scheduling.md"};function t(n,l,h,d,u,s){return e(),i("div",null,[...l[0]||(l[0]=[o('<h1 id="什么是-node、集群与调度" tabindex="-1">什么是 Node、集群与调度 <a class="header-anchor" href="#什么是-node、集群与调度" aria-label="Permalink to &quot;什么是 Node、集群与调度&quot;">​</a></h1><h2 id="一句话定义" tabindex="-1">一句话定义 <a class="header-anchor" href="#一句话定义" aria-label="Permalink to &quot;一句话定义&quot;">​</a></h2><p>CubeSandbox 不是只在一台机器上“跑沙箱”的工具，而是一个可以扩展成多节点系统的平台。</p><p>在这个平台里：</p><ul><li><strong>Node</strong> 是实际承载 Sandbox 的计算节点</li><li><strong>Cluster</strong> 是由多个节点与控制面组成的整体系统</li><li><strong>Scheduling</strong> 是把一个创建请求分配到某个具体节点上的过程</li></ul><p>这三个概念共同决定 CubeSandbox 的伸缩方式和平台形态。</p><h2 id="为什么必须把这三个概念分开" tabindex="-1">为什么必须把这三个概念分开 <a class="header-anchor" href="#为什么必须把这三个概念分开" aria-label="Permalink to &quot;为什么必须把这三个概念分开&quot;">​</a></h2><p>如果只看单机体验，很容易误以为 CubeSandbox 的核心就是：</p><ul><li>一个 API</li><li>一台机器</li><li>若干个沙箱</li></ul><p>但只要系统开始追求：</p><ul><li>更高容量</li><li>更高可用性</li><li>更稳定资源利用率</li><li>不同工作负载分布到不同机器</li></ul><p>就一定会出现三个问题：</p><ol><li><strong>哪台机器来承载这个实例？</strong></li><li><strong>谁来掌握整个系统的资源视图？</strong></li><li><strong>节点和控制面各自负责什么？</strong></li></ol><p>于是 Node、Cluster 和 Scheduling 就成为不可回避的核心概念。</p><h2 id="什么是-node" tabindex="-1">什么是 Node <a class="header-anchor" href="#什么是-node" aria-label="Permalink to &quot;什么是 Node&quot;">​</a></h2><h3 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h3><p>Node 是实际承载 Sandbox 实例的计算节点。</p><p>它通常具备：</p><ul><li>KVM 与底层虚拟化能力</li><li>本地运行时资产</li><li>节点本地调度与生命周期管理组件</li><li>本地网络与存储执行能力</li></ul><h3 id="在-cubesandbox-里的真实角色" tabindex="-1">在 CubeSandbox 里的真实角色 <a class="header-anchor" href="#在-cubesandbox-里的真实角色" aria-label="Permalink to &quot;在 CubeSandbox 里的真实角色&quot;">​</a></h3><p>Node 不是“被动机器”，而是执行面主体。</p><p>它负责真正把一个抽象请求变成活的实例，包括：</p><ul><li>准备 Sandbox 运行时资产</li><li>创建 / 恢复实例</li><li>维护本地网络</li><li>管理实例状态</li><li>回收实例与本地资源</li></ul><p>所以 Node 可以理解成：</p><blockquote><p><strong>控制面意图真正落地的地方。</strong></p></blockquote><h3 id="为什么-node-不是控制面" tabindex="-1">为什么 Node 不是控制面 <a class="header-anchor" href="#为什么-node-不是控制面" aria-label="Permalink to &quot;为什么 Node 不是控制面&quot;">​</a></h3><p>Node 知道“如何执行”，但它通常不应该独自决定“整个系统如何调度”。</p><p>这就是为什么需要 Cluster 和控制面。</p><h2 id="什么是-cluster" tabindex="-1">什么是 Cluster <a class="header-anchor" href="#什么是-cluster" aria-label="Permalink to &quot;什么是 Cluster&quot;">​</a></h2><h3 id="定义-1" tabindex="-1">定义 <a class="header-anchor" href="#定义-1" aria-label="Permalink to &quot;定义&quot;">​</a></h3><p>Cluster 是由控制面和多个 Node 共同构成的 CubeSandbox 整体。</p><p>它的意义不是“机器多了”，而是系统开始拥有了全局视角：</p><ul><li>哪些节点可用</li><li>哪些节点资源充足</li><li>哪些实例在哪些节点上</li><li>模板和实例元数据如何统一管理</li></ul><h3 id="cluster-真正解决什么问题" tabindex="-1">Cluster 真正解决什么问题 <a class="header-anchor" href="#cluster-真正解决什么问题" aria-label="Permalink to &quot;Cluster 真正解决什么问题&quot;">​</a></h3><p>Cluster 解决的是 <strong>全局协调问题</strong>。</p><p>单机时，很多问题可以省略：</p><ul><li>调度目标只有一个</li><li>资源视图天然本地化</li><li>状态一致性更简单</li></ul><p>多机时，这些假设全部失效，平台必须引入控制面视角来维持：</p><ul><li>全局资源认知</li><li>请求分发</li><li>节点注册与健康</li><li>实例与模板元数据统一</li></ul><h3 id="为什么-cluster-不是-多台机器的总称" tabindex="-1">为什么 Cluster 不是“多台机器的总称” <a class="header-anchor" href="#为什么-cluster-不是-多台机器的总称" aria-label="Permalink to &quot;为什么 Cluster 不是“多台机器的总称”&quot;">​</a></h3><p>如果只是多台机器但没有统一控制与调度，它只是机器集合，不是平台级 Cluster。</p><p>Cluster 的本质在于：</p><blockquote><p><strong>系统开始以“整体”而不是“单机脚本”方式组织计算能力。</strong></p></blockquote><h2 id="什么是-scheduling" tabindex="-1">什么是 Scheduling <a class="header-anchor" href="#什么是-scheduling" aria-label="Permalink to &quot;什么是 Scheduling&quot;">​</a></h2><h3 id="定义-2" tabindex="-1">定义 <a class="header-anchor" href="#定义-2" aria-label="Permalink to &quot;定义&quot;">​</a></h3><p>Scheduling（调度）是控制面根据某种规则，把一个 Sandbox 创建请求分配给某个 Node 的过程。</p><h3 id="调度到底在决定什么" tabindex="-1">调度到底在决定什么 <a class="header-anchor" href="#调度到底在决定什么" aria-label="Permalink to &quot;调度到底在决定什么&quot;">​</a></h3><p>调度不是简单“随机选台机器”，而是在回答：</p><ul><li>哪台机器当前更适合承载这个 Sandbox</li><li>该实例所需资源在哪个节点上更容易满足</li><li>是否有模板、网络、节点标签或策略上的约束</li><li>整个系统如何保持容量平衡与稳定性</li></ul><h3 id="为什么调度是平台灵魂之一" tabindex="-1">为什么调度是平台灵魂之一 <a class="header-anchor" href="#为什么调度是平台灵魂之一" aria-label="Permalink to &quot;为什么调度是平台灵魂之一&quot;">​</a></h3><p>一个平台的好坏，很大程度上体现在调度是否正确：</p><ul><li>调度正确，系统更稳定、更高效</li><li>调度错误，单机再强也会出现热点、资源碎片和失败抖动</li></ul><h2 id="cubesandbox-中控制面与节点面的边界" tabindex="-1">CubeSandbox 中控制面与节点面的边界 <a class="header-anchor" href="#cubesandbox-中控制面与节点面的边界" aria-label="Permalink to &quot;CubeSandbox 中控制面与节点面的边界&quot;">​</a></h2><p>这是理解 Node / Cluster 的关键。</p><h3 id="控制面更关心-意图与全局" tabindex="-1">控制面更关心“意图与全局” <a class="header-anchor" href="#控制面更关心-意图与全局" aria-label="Permalink to &quot;控制面更关心“意图与全局”&quot;">​</a></h3><p>控制面主要负责：</p><ul><li>接收外部 API 请求</li><li>维护模板与实例元数据</li><li>感知节点状态</li><li>选择调度目标</li><li>定义全局策略与系统视图</li></ul><p>控制面主要回答的是：</p><blockquote><p>“应该做什么、在哪做、系统整体现在怎样？”</p></blockquote><h3 id="节点面更关心-执行与本地状态" tabindex="-1">节点面更关心“执行与本地状态” <a class="header-anchor" href="#节点面更关心-执行与本地状态" aria-label="Permalink to &quot;节点面更关心“执行与本地状态”&quot;">​</a></h3><p>节点面主要负责：</p><ul><li>真正启动或恢复 Sandbox</li><li>维护本地运行时与网络</li><li>跟踪本地实例状态</li><li>处理回收、清理、重建等动作</li></ul><p>节点面主要回答的是：</p><blockquote><p>“这件事在本机怎么做，当前做到了哪一步？”</p></blockquote><h3 id="为什么这个边界必须清晰" tabindex="-1">为什么这个边界必须清晰 <a class="header-anchor" href="#为什么这个边界必须清晰" aria-label="Permalink to &quot;为什么这个边界必须清晰&quot;">​</a></h3><p>如果控制面管得太细，会失去伸缩性； 如果节点面过于自治，又会丢掉全局协调能力。</p><p>所以健康的平台通常遵循：</p><ul><li>控制面做全局决策</li><li>节点面做本地执行</li></ul><p>CubeSandbox 的整体设计也符合这个方向。</p><h2 id="一次请求如何穿过这三层概念" tabindex="-1">一次请求如何穿过这三层概念 <a class="header-anchor" href="#一次请求如何穿过这三层概念" aria-label="Permalink to &quot;一次请求如何穿过这三层概念&quot;">​</a></h2><p>可以把一次 Sandbox 创建简化成下面的思路：</p><ol><li>用户向控制面发起请求</li><li>控制面解析请求涉及的 Template、规格和策略</li><li>调度逻辑选择一个合适的 Node</li><li>该 Node 的本地组件开始实例化 Sandbox</li><li>节点反馈状态给控制面</li><li>控制面把最终可访问结果返回给用户</li></ol><p>这条链路说明：</p><ul><li>请求是全局进入的</li><li>实例是本地落地的</li><li>调度是中间的桥梁</li></ul><h2 id="node-视角下最重要的本地职责" tabindex="-1">Node 视角下最重要的本地职责 <a class="header-anchor" href="#node-视角下最重要的本地职责" aria-label="Permalink to &quot;Node 视角下最重要的本地职责&quot;">​</a></h2><p>如果你从节点视角看，真正关键的不是“自己是集群成员”这一身份，而是它要承接的本地职责。</p><h3 id="_1-本地生命周期管理" tabindex="-1">1. 本地生命周期管理 <a class="header-anchor" href="#_1-本地生命周期管理" aria-label="Permalink to &quot;1. 本地生命周期管理&quot;">​</a></h3><p>节点必须能可靠地：</p><ul><li>创建实例</li><li>查询实例状态</li><li>回收实例</li><li>恢复必要状态</li></ul><h3 id="_2-本地资源管理" tabindex="-1">2. 本地资源管理 <a class="header-anchor" href="#_2-本地资源管理" aria-label="Permalink to &quot;2. 本地资源管理&quot;">​</a></h3><p>节点要知道本机有哪些资源可用于 Sandbox：</p><ul><li>CPU / 内存</li><li>本地网络对象</li><li>本地存储空间</li><li>运行时 socket 与目录</li></ul><h3 id="_3-本地故障吸收" tabindex="-1">3. 本地故障吸收 <a class="header-anchor" href="#_3-本地故障吸收" aria-label="Permalink to &quot;3. 本地故障吸收&quot;">​</a></h3><p>一个稳定平台不应该把所有小故障都放大成全局事故。</p><p>节点需要尽量在本地处理：</p><ul><li>清理失败实例</li><li>回收损坏状态</li><li>重建本地运行时关联</li></ul><h2 id="cluster-视角下最重要的全局职责" tabindex="-1">Cluster 视角下最重要的全局职责 <a class="header-anchor" href="#cluster-视角下最重要的全局职责" aria-label="Permalink to &quot;Cluster 视角下最重要的全局职责&quot;">​</a></h2><p>如果你从 Cluster 视角看，最重要的是保持“全局一致认知”。</p><h3 id="_1-节点健康认知" tabindex="-1">1. 节点健康认知 <a class="header-anchor" href="#_1-节点健康认知" aria-label="Permalink to &quot;1. 节点健康认知&quot;">​</a></h3><p>系统需要知道：</p><ul><li>哪些节点在线</li><li>哪些节点可调度</li><li>哪些节点资源不足</li><li>哪些节点应被摘除或降级</li></ul><h3 id="_2-实例位置认知" tabindex="-1">2. 实例位置认知 <a class="header-anchor" href="#_2-实例位置认知" aria-label="Permalink to &quot;2. 实例位置认知&quot;">​</a></h3><p>控制面需要知道某个 Sandbox 当前在哪个节点，否则就无法：</p><ul><li>查询状态</li><li>路由请求</li><li>做后续运维</li></ul><h3 id="_3-资源分布认知" tabindex="-1">3. 资源分布认知 <a class="header-anchor" href="#_3-资源分布认知" aria-label="Permalink to &quot;3. 资源分布认知&quot;">​</a></h3><p>调度不是一次性动作，而是持续依赖全局资源视图。</p><h2 id="调度到底以什么为依据" tabindex="-1">调度到底以什么为依据 <a class="header-anchor" href="#调度到底以什么为依据" aria-label="Permalink to &quot;调度到底以什么为依据&quot;">​</a></h2><p>具体算法可以演进，但概念上通常会参考以下维度：</p><ul><li>节点可用性</li><li>剩余资源</li><li>节点标签或角色</li><li>模板或运行时依赖</li><li>网络与访问路径要求</li><li>平衡策略与热点规避</li></ul><p>所以调度不是“选一个节点”，而是“在多个约束和优化目标之间做选择”。</p><h2 id="为什么多节点能力对-cubesandbox-很关键" tabindex="-1">为什么多节点能力对 CubeSandbox 很关键 <a class="header-anchor" href="#为什么多节点能力对-cubesandbox-很关键" aria-label="Permalink to &quot;为什么多节点能力对 CubeSandbox 很关键&quot;">​</a></h2><p>CubeSandbox 的一个核心价值是：</p><ul><li>单节点上可以高密度运行大量 Sandbox</li><li>同时又可以扩展到多节点集群</li></ul><p>这意味着它既要有 <strong>单机高密度能力</strong>，也要有 <strong>集群扩展能力</strong>。</p><p>如果没有 Node / Cluster / Scheduling 这套概念，系统就只能停留在“单机演示很强”的阶段，无法真正成为平台。</p><h2 id="常见误解" tabindex="-1">常见误解 <a class="header-anchor" href="#常见误解" aria-label="Permalink to &quot;常见误解&quot;">​</a></h2><h3 id="误解一-既然单机能跑很多实例-集群调度就没那么重要" tabindex="-1">误解一：既然单机能跑很多实例，集群调度就没那么重要 <a class="header-anchor" href="#误解一-既然单机能跑很多实例-集群调度就没那么重要" aria-label="Permalink to &quot;误解一：既然单机能跑很多实例，集群调度就没那么重要&quot;">​</a></h3><p>不对。</p><p>单机高密度解决的是单节点效率；集群调度解决的是整体容量和分布问题。两者不是替代关系。</p><h3 id="误解二-调度就是控制面决定完-节点只照做" tabindex="-1">误解二：调度就是控制面决定完，节点只照做 <a class="header-anchor" href="#误解二-调度就是控制面决定完-节点只照做" aria-label="Permalink to &quot;误解二：调度就是控制面决定完，节点只照做&quot;">​</a></h3><p>不完全对。</p><p>控制面决定目标节点，但节点面仍然承担大量实际可执行性判断与本地状态处理。没有强节点执行能力，调度只是一纸命令。</p><h3 id="误解三-node-只是-安装了-cubelet-的机器" tabindex="-1">误解三：Node 只是“安装了 Cubelet 的机器” <a class="header-anchor" href="#误解三-node-只是-安装了-cubelet-的机器" aria-label="Permalink to &quot;误解三：Node 只是“安装了 Cubelet 的机器”&quot;">​</a></h3><p>不够准确。</p><p>Node 是平台运行时能力、网络能力、存储能力和本地生命周期能力的实际承载者，而不只是装了一个进程的机器。</p><h2 id="对运维和平台设计的意义" tabindex="-1">对运维和平台设计的意义 <a class="header-anchor" href="#对运维和平台设计的意义" aria-label="Permalink to &quot;对运维和平台设计的意义&quot;">​</a></h2><p>如果你是运维或架构角色，理解这组概念时最该抓住的是：</p><ol><li><strong>Cluster 决定平台上限。</strong></li><li><strong>Node 决定实例落地质量。</strong></li><li><strong>Scheduling 决定资源分布与体验稳定性。</strong></li></ol><p>很多线上问题最后都可以归结到这三层之一：</p><ul><li>调度选错节点</li><li>节点本地状态不健康</li><li>控制面对全局状态认知不完整</li></ul><h2 id="和相关文档的关系" tabindex="-1">和相关文档的关系 <a class="header-anchor" href="#和相关文档的关系" aria-label="Permalink to &quot;和相关文档的关系&quot;">​</a></h2><ul><li>想看控制面与组件概览： <a href="./../../architecture/overview.html">架构概览</a></li><li>想看节点配置与运行时路径： <a href="./../ops-manual/03-node-runtime-config.html">节点与运行时配置文件路径与说明</a></li><li>想看控制面配置： <a href="./../ops-manual/02-control-plane-config.html">控制面配置文件路径与说明</a></li><li>想看网络概念： <a href="./network-exposure.html">什么是网络、暴露端口与访问路径</a></li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>理解了实例被谁承载、如何调度之后，下一个问题通常是：</p><p><strong>这些 Sandbox 创建出来后，到底如何联网、如何暴露服务、外部又是怎么访问进去的？</strong></p><p>这就进入网络概念： <a href="./network-exposure.html">什么是网络、暴露端口与访问路径</a>。</p>',126)])])}const b=a(r,[["render",t]]);export{c as __pageData,b as default};
